INSERT INTO banners (id, title, image_url, link_url, is_active, sort_order, "position", subtitle_kk, subtitle_ru, created_at) VALUES ('00000000-0000-4000-8000-000000000901', 'Тіл-құралға қош келдіңіз', 'https://images.unsplash.com/photo-1524995997946-a1c2e315a42f?w=1600&q=80', '/ru/learn', true, 10, 'hero', 'Қазақ тілін AI-тәлімгермен үйреніңіз', 'Учите казахский язык с AI-учителем', '2026-04-21 21:37:31.071746+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO banners (id, title, image_url, link_url, is_active, sort_order, "position", subtitle_kk, subtitle_ru, created_at) VALUES ('00000000-0000-4000-8000-000000000902', 'Пройди тест уровня', 'https://images.unsplash.com/photo-1434030216411-0b793f4b4173?w=1600&q=80', '/ru/test', true, 20, 'hero', 'Қазақ тілі деңгейіңізді 5 минутта анықтаңыз', 'Определите ваш уровень казахского за 5 минут', '2026-04-21 21:37:31.071746+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO banners (id, title, image_url, link_url, is_active, sort_order, "position", subtitle_kk, subtitle_ru, created_at) VALUES ('00000000-0000-4000-8000-000000000903', 'Новый курс KAZTEST', 'https://images.unsplash.com/photo-1509062522246-3755977927d7?w=1600&q=80', '/ru/learn/kaztest', true, 30, 'hero', 'KAZTEST емтиханына толық дайындық — 5 секция', 'Полная подготовка к KAZTEST — 5 секций', '2026-04-21 21:37:31.071746+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO grammar_rules (id, topic, title_kk, title_ru, level, description_kk, description_ru, examples, exceptions, rule_order, created_at) VALUES ('rule_03', 'Зат есім', 'Зат есімнің көптік жалғауы', 'Множественное число существительных', 'A1', 'Көптік жалғау -лар/-лер, -дар/-дер, -тар/-тер. Сөз соңындағы дыбысқа және буын үндестігіне байланысты таңдалады.', 'Окончания множественного числа: -лар/-лер, -дар/-дер, -тар/-тер. Выбор зависит от последнего звука и гармонии гласных.', '["бала-лар", "үй-лер", "ат-тар", "күн-дер", "жол-дар", "гүл-дер"]', '[]', 30, '2026-04-21 21:35:28.437388+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO grammar_rules (id, topic, title_kk, title_ru, level, description_kk, description_ru, examples, exceptions, rule_order, created_at) VALUES ('rule_04', 'Зат есім', 'Септік жалғаулары', 'Падежные окончания', 'A2', 'Қазақ тілінде 7 септік бар: атау, ілік, барыс, табыс, жатыс, шығыс, көмектес.', 'В казахском языке 7 падежей: именительный, родительный, дательный, винительный, местный, исходный, творительный.', '["бала (атау)", "баланың (ілік)", "балаға (барыс)", "баланы (табыс)", "балада (жатыс)", "баладан (шығыс)", "баламен (көмектес)"]', '[]', 40, '2026-04-21 21:35:28.437388+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO grammar_rules (id, topic, title_kk, title_ru, level, description_kk, description_ru, examples, exceptions, rule_order, created_at) VALUES ('rule_06', 'Сын есім', 'Сын есімнің шырайлары', 'Степени сравнения прилагательных', 'B1', 'Сын есімнің 4 шырайы бар: жай шырай (қосымшасыз: үлкен), салыстырмалы шырай (-рақ/-рек, -ырақ/-ірек, -лау/-леу: үлкенірек), күшейтпелі шырай (буын қайталау: қып-қызыл, көп-көк), асырмалы шырай (ең, тым, өте, аса: ең үлкен).', 'Четыре степени: положительная (без аффикса: үлкен), сравнительная (-рақ/-рек, -ырақ/-ірек, -лау/-леу: үлкенірек), эмфатическая / күшейтпелі (повтор слога: қып-қызыл, көп-көк), превосходная / асырмалы (ең, тым, өте, аса: ең үлкен).', '["үлкен → үлкенірек → ең үлкен", "жақсы → жақсырақ → ең жақсы", "қызыл → қып-қызыл (күшейтпелі)"]', '[]', 60, '2026-04-21 21:35:28.437388+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO grammar_rules (id, topic, title_kk, title_ru, level, description_kk, description_ru, examples, exceptions, rule_order, created_at) VALUES ('rule_08', 'Етістік', 'Етістіктің шақтары: Өткен шақ', 'Времена глагола: Прошедшее время', 'A2', 'Жедел өткен шақ: -ды/-ді, -ты/-ті (жақын, көзбен көрілген әрекет). Бұрынғы өткен шақ: -ған/-ген, -қан/-кен (нәтижелі, перфектілі мән).', 'Недавнопрошедшее (очевидное): -ды/-ді, -ты/-ті — действие, свидетелем которого был говорящий. Перфектное (результативное): -ған/-ген, -қан/-кен — результат сохраняется к моменту речи.', '["Мен бардым (жедел/недавнопрошедшее)", "Мен барғанмын (перфектное)", "Ол келді", "Ол келген"]', '[]', 80, '2026-04-21 21:35:28.437388+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO grammar_rules (id, topic, title_kk, title_ru, level, description_kk, description_ru, examples, exceptions, rule_order, created_at) VALUES ('rule_09', 'Етістік', 'Етістіктің шақтары: Келер шақ', 'Времена глагола: Будущее время', 'B1', 'Болжалды келер шақ: -ар/-ер дауыссыздан кейін, -р дауыстыдан кейін (мүмкіндік мағынасы). Мақсатты (намерение): -мақ/-мек, -бақ/-бек, -пақ/-пек.', 'Будущее предположительное: -ар/-ер после согласного, -р после гласного (значение «возможно сделает»). Будущее намерения: -мақ/-мек, -бақ/-бек, -пақ/-пек (значение «намерен сделать»).', '["Мен барармын", "Ол келер", "Мен оқымақпын", "Ол жаз-бақ"]', '[]', 90, '2026-04-21 21:35:28.437388+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO grammar_rules (id, topic, title_kk, title_ru, level, description_kk, description_ru, examples, exceptions, rule_order, created_at) VALUES ('rule_10', 'Етістік', 'Етістіктің болымсыз түрі', 'Отрицательная форма глагола', 'A1', 'Болымсыздық -ма/-ме, -ба/-бе, -па/-пе жұрнақтарымен жасалады.', 'Отрицание образуется суффиксами -ма/-ме, -ба/-бе, -па/-пе.', '["бар-ма-ды", "кел-ме-ді", "жаз-ба-ды", "оқы-ма-ды"]', '[]', 100, '2026-04-21 21:35:28.437388+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO grammar_rules (id, topic, title_kk, title_ru, level, description_kk, description_ru, examples, exceptions, rule_order, created_at) VALUES ('rule_12', 'Сөйлем құрылымы', 'Сұраулы сөйлемдер', 'Вопросительные предложения', 'A1', 'Сұрау есімдіктері: кім, не, қайда, қашан, неше, қалай, неге. Немесе сұраулық демеулік шылаулар арқылы: ма/ме, ба/бе, па/пе (сөздің соңғы дыбысына сай таңдалады).', 'Вопросительные местоимения: кім, не, қайда, қашан, неше, қалай, неге. Или вопросительные частицы (демеулік шылау): ма/ме, ба/бе, па/пе (выбираются по последнему звуку слова).', '["Сен қайда барасың?", "Бұл кітап па?", "Ол кім?", "Ол келді ме?"]', '[]', 120, '2026-04-21 21:35:28.437388+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO grammar_rules (id, topic, title_kk, title_ru, level, description_kk, description_ru, examples, exceptions, rule_order, created_at) VALUES ('rule_14', 'Сан есім', 'Сан есімдер және есептеу', 'Числительные и счёт', 'A1', 'Қазақ тілінде сан есімнен кейін зат есімге көптік жалғау жалғанбайды.', 'В казахском языке после числительного существительное не получает окончание множественного числа.', '["бес бала (дұрыс емес: бес балалар)", "он кітап (дұрыс емес: он кітаптар)", "үш күн"]', '[]', 140, '2026-04-21 21:35:28.437388+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO grammar_rules (id, topic, title_kk, title_ru, level, description_kk, description_ru, examples, exceptions, rule_order, created_at) VALUES ('rule_15', 'Есімдік', 'Жіктеу есімдіктері', 'Личные местоимения', 'A1', 'Мен, сен, сіз, ол, біз, сендер, сіздер, олар. Сіз — құрмет формасы.', 'Мен (я), сен (ты), Сіз (Вы — вежл.), ол (он/она), біз (мы), сендер (вы — мн.), Сіздер (Вы — мн. вежл.), олар (они). Сіз — вежливая форма.', '["Мен студентпін", "Сіз мұғалімсіз", "Олар оқиды"]', '[]', 150, '2026-04-21 21:35:28.437388+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO grammar_rules (id, topic, title_kk, title_ru, level, description_kk, description_ru, examples, exceptions, rule_order, created_at) VALUES ('rule_01', 'Дыбыс үндестігі', 'Буын үндестігі (сингармонизм)', 'Гармония гласных (сингармонизм)', 'A1', 'Қазақ тілінде жуан дауысты дыбыстар мен жіңішке дауысты дыбыстар бір сөзде араласып қолданылмайды.', 'В казахском языке твёрдые и мягкие гласные не смешиваются в одном слове.', '["бала-лар (жуан)", "тіл-дер (жіңішке)", "кітап-тар (жуан)"]', '["Кейбір кірме сөздерде буын үндестігі сақталмайды"]', 10, '2026-04-21 21:35:28.437388+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO grammar_rules (id, topic, title_kk, title_ru, level, description_kk, description_ru, examples, exceptions, rule_order, created_at) VALUES ('rule_02', 'Дыбыс үндестігі', 'Үндестік заңы - дауыссыз дыбыстар үндесуі', 'Ассимиляция согласных', 'A1', 'Қосымшаның басқы дыбысы сөздің соңғы дыбысына үндесіп өзгереді: қатаң дыбыстан кейін қатаң (-тан/-тен), ұяң не үнді дыбыстан кейін ұяң (-дан/-ден), дауыстыдан кейін де ұяң (-дан/-ден) қосымша жалғанады.', 'Начальный звук аффикса ассимилируется с конечным звуком основы. После глухого согласного — глухой вариант (-тан/-тен), после звонкого или сонорного — звонкий (-дан/-ден) ON CONFLICT (id) DO NOTHING; после гласного — также звонкий (-дан/-ден).', '["тас-тан (қатаң+қатаң)", "қала-дан (дауысты+ұяң)", "мал-дан (үнді+ұяң)", "қыз-дан (ұяң+ұяң)"]', '[]', 20, '2026-04-21 21:35:28.437388+00');
INSERT INTO grammar_rules (id, topic, title_kk, title_ru, level, description_kk, description_ru, examples, exceptions, rule_order, created_at) VALUES ('rule_05', 'Зат есім', 'Тәуелдік жалғаулары', 'Притяжательные окончания', 'A2', 'Тәуелдік жалғаулары заттың кімдікі екенін білдіреді: -м/-ым/-ім (менің), -ң/-ың/-ің (сенің), -ңыз/-ңіз (Сіздің), -сы/-сі (оның), -мыз/-міз/-ымыз/-іміз (біздің), -ларың/-леріңіз (сендердің/Сіздердің), -лары/-лері (олардың).', 'Притяжательные окончания показывают, чьим является предмет (вопрос «кімдікі?»). Имеют твёрдые и мягкие варианты по гармонии гласных.', '["үй-ім (мой дом)", "үй-ің (твой дом)", "үй-і (его дом)", "үй-іміз (наш дом)", "кітаб-ым (п→б перед гласной)"]', '["Дауыссызға аяқталған негізде дауыстыдан басталатын тәуелдік жалғауы алдында п→б, к→г, қ→ғ алмасуы мүмкін: кітап → кітабым, тарақ → тарағым."]', 50, '2026-04-21 21:35:28.437388+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO grammar_rules (id, topic, title_kk, title_ru, level, description_kk, description_ru, examples, exceptions, rule_order, created_at) VALUES ('rule_07', 'Етістік', 'Етістіктің шақтары: Осы шақ', 'Времена глагола: Настоящее время', 'A2', 'Нақ осы шақ көсемше қосымшасы (-п дауыстыдан кейін; -ып/-іп дауыссыздан кейін, буын үндестігіне сай) + жатыр/отыр/тұр/жүр көмекші етістіктерімен жасалады.', 'Настоящее (актуальное) время образуется деепричастной формой (-п после гласного; -ып/-іп после согласного, по гармонии гласных) + вспомогательные глаголы жатыр/отыр/тұр/жүр.', '["Мен оқып жатырмын", "Сен жазып отырсың", "Олар сабақ оқып жүр", "Ол кел-іп жатыр"]', '[]', 70, '2026-04-21 21:35:28.437388+00');
INSERT INTO grammar_rules (id, topic, title_kk, title_ru, level, description_kk, description_ru, examples, exceptions, rule_order, created_at) VALUES ('rule_11', 'Сөйлем құрылымы', 'Сөйлемдегі сөздердің орын тәртібі', 'Порядок слов в предложении', 'A1', 'Қазақ тілі — SOV-тіл. Негізгі тәртіп: Бастауыш + Толықтауыш + Баяндауыш. Пысықтауыш әдетте бастауыш пен баяндауыштың арасында тұрады, орны икемді.', 'Казахский — язык SOV. Базовый порядок: Подлежащее + Дополнение + Сказуемое. Обстоятельства располагаются гибко, чаще между подлежащим и сказуемым.', '["Мен кітап оқыдым (Я читал книгу)", "Бала мектепке барды (Ребёнок пошёл в школу)"]', '["Сұраулы сөйлемдерде сөз тәртібі өзгеруі мүмкін"]', 110, '2026-04-21 21:35:28.437388+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO grammar_rules (id, topic, title_kk, title_ru, level, description_kk, description_ru, examples, exceptions, rule_order, created_at) VALUES ('rule_18', 'Фонетика', 'Қазақ тіліне тән дыбыстар', 'Специфические звуки казахского языка', 'A1', 'Қазақ тілінде 9 тән дыбыс бар: ә, і, ө, ү, ұ, қ, ғ, ң, һ.', 'В казахском языке 9 специфических звуков: ә, і, ө, ү, ұ, қ, ғ, ң, һ.', '["Ә — әке (отец)", "Қ — қала (город)", "Ғ — тағам (еда)", "Ң — таң (рассвет)", "Ұ — ұл (сын)", "Ө — өзен (река)"]', '[]', 180, '2026-04-21 21:35:28.437388+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO grammar_rules (id, topic, title_kk, title_ru, level, description_kk, description_ru, examples, exceptions, rule_order, created_at) VALUES ('rule_19', 'Емле', 'Бас әріп ережелері', 'Правила заглавной буквы', 'A2', 'Бас әріппен жазылады: сөйлем басы, жалқы есімдер, географиялық атаулар, мемлекет атаулары, мекемелер мен ұйымдардың аттары.', 'С заглавной буквы: начало предложения, имена собственные, географические названия, названия государств, наименования учреждений и организаций.', '["Астана", "Абай Құнанбайұлы", "Қазақстан Республикасы", "Әл-Фараби атындағы ҚазҰУ"]', '[]', 190, '2026-04-21 21:35:28.437388+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO grammar_rules (id, topic, title_kk, title_ru, level, description_kk, description_ru, examples, exceptions, rule_order, created_at) VALUES ('rule_21', 'Мақал-мәтелдер', 'Қазақ мақал-мәтелдері', 'Казахские пословицы и поговорки', 'B1', 'Мақал-мәтелдер — халық даналығының айнасы. Тіл үйренуде маңызды.', 'Пословицы и поговорки — зеркало народной мудрости. Важны при изучении языка.', '["Тіл — қылыштан өткір", "Білімді мың жасайды", "Еңбек етсең ерінбей, тояды қарның тіленбей", "Жақсы сөз — жарым ырыс"]', '[]', 210, '2026-04-21 21:35:28.437388+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO grammar_rules (id, topic, title_kk, title_ru, level, description_kk, description_ru, examples, exceptions, rule_order, created_at) VALUES ('rule_13', 'Шылаулар', 'Септеулік шылаулар', 'Послелоги', 'B1', 'Септеулік шылаулар зат есімнен кейін тұрып, мекенді, уақытты, себепті білдіреді: үшін, туралы, арқылы, бойынша, сияқты, т.б. Әр шылау өзінен бұрынғы сөздің белгілі септік формасын талап етеді (есімдіктерден кейін «үшін», «туралы» — ілік септігін, ал зат есімдерден кейін атау септігін талап етеді).', 'Послелоги стоят после существительного и выражают место, время, причину: үшін, туралы, арқылы, бойынша, сияқты и т.д. Каждый послелог требует определённой падежной формы предшествующего слова (после местоимений «үшін», «туралы» — родительный падеж, после существительных — именительный).', '["сен үшін (для тебя)", "тіл туралы (о языке)", "көпір арқылы (через мост)", "менің ойымша (по моему мнению)"]', '[]', 130, '2026-04-21 21:35:28.437388+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO grammar_rules (id, topic, title_kk, title_ru, level, description_kk, description_ru, examples, exceptions, rule_order, created_at) VALUES ('rule_16', 'Жұрнақтар', 'Сөз тудырушы жұрнақтар', 'Словообразовательные суффиксы', 'B1', 'Зат есімнен сын есім: -лы/-лі, -ды/-ді, -сыз/-сіз. Етістіктен зат есім: -ыс/-іс, -у (тұйық етістік / іс-әрекеттің атауы).', 'От существительного к прилагательному: -лы/-лі, -ды/-ді, -сыз/-сіз. От глагола к существительному: -ыс/-іс, -у (имя действия / отглагольное существительное).', '["күш-ті (сильный)", "су-сыз (безводный)", "оқу (учёба/чтение)", "жаз-у (письмо)"]', '[]', 160, '2026-04-21 21:35:28.437388+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO grammar_rules (id, topic, title_kk, title_ru, level, description_kk, description_ru, examples, exceptions, rule_order, created_at) VALUES ('rule_17', 'Етістік', 'Етістіктің рай категориясы', 'Наклонения глагола', 'B2', 'Ашық рай (баяндау, шақ жұрнақтары арқылы) ON CONFLICT (id) DO NOTHING; бұйрық рай — нөлдік форма (бар!, кел!), жұмсартқан -шы/-ші (баршы, келші), құрметті -ңыз/-ңіз (барыңыз, келіңіз); қалау рай (-ғы/-гі келеді: барғым келеді); шартты рай (-са/-се: келсе).', 'Изъявительное (баяндау, через временные суффиксы); повелительное — нулевая форма для 2-го л. ед.ч. (бар!, кел!), смягчённое -шы/-ші (баршы — «иди-ка»), вежливое -ңыз/-ңіз (барыңыз); желательное (-ғы/-гі келеді: барғым келеді — «хочу пойти»); условное (-са/-се: келсе — «если придёт»).', '["Бар! (иди!)", "Бар-шы! (иди же!)", "Бар-ыңыз (пройдите, пожалуйста)", "Мен бар-ғым келеді (хочу пойти)", "Ол кел-се (если он придёт)"]', '[]', 170, '2026-04-21 21:35:28.437388+00');
INSERT INTO grammar_rules (id, topic, title_kk, title_ru, level, description_kk, description_ru, examples, exceptions, rule_order, created_at) VALUES ('rule_20', 'Етістік', 'Есімше формалары', 'Причастные формы', 'B2', 'Есімше — етістіктің сын есім тәрізді формасы: -ған/-ген/-қан/-кен (өткен шақ есімшесі), -атын/-етін/-йтын/-йтін (дағдылы), -ар/-ер/-р (келер шақ есімшесі), -мақ/-мек (мақсатты).', 'Причастие — глагольная форма, подобная прилагательному: -ған/-ген/-қан/-кен (прошедшее), -атын/-етін/-йтын/-йтін (привычное/настояще-будущее), -ар/-ер/-р (будущее), -мақ/-мек (намеренное).', '["келген адам (пришедший человек)", "оқитын бала (ребёнок, который учится)", "барар жер (место, куда пойдёт)"]', '[]', 200, '2026-04-21 21:35:28.437388+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, title_kk, title_ru, description_kk, description_ru, topic, difficulty, content, sort_order, created_at, mentor_track, required_level) VALUES ('00000000-0000-4000-8000-000000001002', 'Сандар мен уақыт', 'Числа и время', '1-ден 100-ге дейінгі сандар, уақытты айту.', 'Числа от 1 до 100, как называть время.', 'vocabulary', 'A1', '{"rule_ids": []}', 2, '2026-04-21 21:35:28.434024+00', 'auezov', 'A1') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, title_kk, title_ru, description_kk, description_ru, topic, difficulty, content, sort_order, created_at, mentor_track, required_level) VALUES ('00000000-0000-4000-8000-000000001003', 'Менің отбасым', 'Моя семья', 'Отбасы мүшелерінің атаулары, тәуелдік жалғаулары.', 'Названия членов семьи, притяжательные окончания.', 'vocabulary', 'A1', '{"rule_ids": ["rule_05"]}', 3, '2026-04-21 21:35:28.434024+00', 'auezov', 'A1') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, title_kk, title_ru, description_kk, description_ru, topic, difficulty, content, sort_order, created_at, mentor_track, required_level) VALUES ('00000000-0000-4000-8000-000000001004', 'Көптік жалғау', 'Множественное число', 'Көптік жалғауларының (-лар/-лер/-дар/-дер/-тар/-тер) қолданылуы.', 'Использование окончаний множественного числа.', 'grammar', 'A1', '{"rule_ids": ["rule_03", "rule_01", "rule_02"]}', 4, '2026-04-21 21:35:28.434024+00', 'baitursynuly', 'A2') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, title_kk, title_ru, description_kk, description_ru, topic, difficulty, content, sort_order, created_at, mentor_track, required_level) VALUES ('00000000-0000-4000-8000-000000001005', 'Дүкенде сатып алу', 'Покупки в магазине', 'Дүкенде сөйлесу, баға сұрау, сауда жасасу.', 'Разговор в магазине, вопросы о цене, обсуждение покупки.', 'conversation', 'A2', '{"rule_ids": []}', 5, '2026-04-21 21:35:28.434024+00', 'auezov', 'B1') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, title_kk, title_ru, description_kk, description_ru, topic, difficulty, content, sort_order, created_at, mentor_track, required_level) VALUES ('00000000-0000-4000-8000-000000001006', 'Септік жалғаулары', 'Падежные окончания', 'Қазақ тіліндегі 7 септік және олардың жалғаулары.', '7 падежей казахского языка и их окончания.', 'grammar', 'A2', '{"rule_ids": ["rule_04", "rule_02"]}', 6, '2026-04-21 21:35:28.434024+00', 'baitursynuly', 'A2') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, title_kk, title_ru, description_kk, description_ru, topic, difficulty, content, sort_order, created_at, mentor_track, required_level) VALUES ('00000000-0000-4000-8000-000000001007', 'Етістік шақтары', 'Времена глагола', 'Осы, өткен және келер шақ жасалуы.', 'Образование настоящего, прошедшего и будущего времён.', 'grammar', 'A2', '{"rule_ids": ["rule_07", "rule_08", "rule_09", "rule_10"]}', 7, '2026-04-21 21:35:28.434024+00', 'baitursynuly', 'B2') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, title_kk, title_ru, description_kk, description_ru, topic, difficulty, content, sort_order, created_at, mentor_track, required_level) VALUES ('00000000-0000-4000-8000-000000001008', 'Мейрамханада тапсырыс', 'Заказ в ресторане', 'Тапсырыс беру, тағамдар атаулары.', 'Сделать заказ, названия блюд.', 'conversation', 'B1', '{"rule_ids": []}', 8, '2026-04-21 21:35:28.434024+00', 'auezov', 'B2') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, title_kk, title_ru, description_kk, description_ru, topic, difficulty, content, sort_order, created_at, mentor_track, required_level) VALUES ('00000000-0000-4000-8000-000000001009', 'Сын есімнің шырайлары', 'Степени сравнения прилагательных', 'Жай, салыстырмалы, күшейтпелі, асырмалы шырайлар.', 'Положительная, сравнительная, эмфатическая (күшейтпелі), превосходная (асырмалы) степени.', 'grammar', 'B1', '{"rule_ids": ["rule_06"]}', 9, '2026-04-21 21:35:28.434024+00', 'baitursynuly', 'B1') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, title_kk, title_ru, description_kk, description_ru, topic, difficulty, content, sort_order, created_at, mentor_track, required_level) VALUES ('00000000-0000-4000-8000-000000001010', 'Іскерлік қазақ тілі', 'Деловой казахский', 'Іскерлік хат, ресми стиль, сыпайы тұлғалар.', 'Деловое письмо, официальный стиль, вежливые формы.', 'business', 'B2', '{"rule_ids": []}', 10, '2026-04-21 21:35:28.434024+00', 'abai', 'C1') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, title_kk, title_ru, description_kk, description_ru, topic, difficulty, content, sort_order, created_at, mentor_track, required_level) VALUES ('00000000-0000-4000-8000-000000001011', 'Сөйлемдегі сөздердің орны', 'Порядок слов в предложении', 'Қазақ тілінде SOV құрылымы: бастауыш–толықтауыш–баяндауыш.', 'Казахский — SOV-язык: подлежащее, дополнение, сказуемое.', 'grammar', 'A2', '{"rule_ids": ["rule_11"]}', 11, '2026-04-21 21:35:28.434024+00', 'baitursynuly', 'A2') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, title_kk, title_ru, description_kk, description_ru, topic, difficulty, content, sort_order, created_at, mentor_track, required_level) VALUES ('00000000-0000-4000-8000-000000001012', 'Сұраулы сөйлемдер', 'Вопросительные предложения', 'Ма/ме/ба/бе сұраулық шылауы, сұрау сөздер, интонация.', 'Вопросительные частицы ма/ме/ба/бе, вопросительные слова.', 'grammar', 'A1', '{"rule_ids": ["rule_12"]}', 12, '2026-04-21 21:35:28.434024+00', 'baitursynuly', 'A1') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, title_kk, title_ru, description_kk, description_ru, topic, difficulty, content, sort_order, created_at, mentor_track, required_level) VALUES ('00000000-0000-4000-8000-000000001013', 'Септеулік шылаулар', 'Послелоги', 'Арқылы, үшін, туралы, бойынша, қарсы — септеулік шылаулардың қолданылуы.', 'Послелоги арқылы, үшін, туралы, бойынша, қарсы и их употребление.', 'grammar', 'B1', '{"rule_ids": ["rule_13"]}', 13, '2026-04-21 21:35:28.434024+00', 'baitursynuly', 'B1') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, title_kk, title_ru, description_kk, description_ru, topic, difficulty, content, sort_order, created_at, mentor_track, required_level) VALUES ('00000000-0000-4000-8000-000000001014', 'Сан есімдер және есептеу', 'Числительные и счёт', 'Есептік, реттік, жинақтық, болжалдық сан есімдер.', 'Количественные, порядковые, собирательные, приблизительные числительные.', 'grammar', 'A1', '{"rule_ids": ["rule_14"]}', 14, '2026-04-21 21:35:28.434024+00', 'baitursynuly', 'A1') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, title_kk, title_ru, description_kk, description_ru, topic, difficulty, content, sort_order, created_at, mentor_track, required_level) VALUES ('00000000-0000-4000-8000-000000001015', 'Жіктеу есімдіктері', 'Личные местоимения', 'Мен, сен, сіз, ол, біз, сендер, сіздер, олар — жіктелуі.', 'Я, ты, Вы (вежл.), он/она, мы, вы (мн.), Вы (мн. вежл.), они — склонение по лицам и числам.', 'grammar', 'A1', '{"rule_ids": ["rule_15"]}', 15, '2026-04-21 21:35:28.434024+00', 'auezov', 'A1') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, title_kk, title_ru, description_kk, description_ru, topic, difficulty, content, sort_order, created_at, mentor_track, required_level) VALUES ('00000000-0000-4000-8000-000000001016', 'Сөз тудырушы жұрнақтар', 'Словообразовательные суффиксы', '-шы/-ші, -лық/-лік, -хана, -стан және басқа сөз тудырушы жұрнақтар.', 'Суффиксы -шы/-ші, -лық/-лік, -хана, -стан и другие словообразовательные.', 'grammar', 'B1', '{"rule_ids": ["rule_16"]}', 16, '2026-04-21 21:35:28.434024+00', 'baitursynuly', 'B1') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, title_kk, title_ru, description_kk, description_ru, topic, difficulty, content, sort_order, created_at, mentor_track, required_level) VALUES ('00000000-0000-4000-8000-000000001017', 'Етістіктің рай категориясы', 'Наклонения глагола', 'Ашық, бұйрық, шартты, қалау райлары.', 'Изъявительное, повелительное, условное, желательное наклонения.', 'grammar', 'B2', '{"rule_ids": ["rule_17"]}', 17, '2026-04-21 21:35:28.434024+00', 'baitursynuly', 'B2') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, title_kk, title_ru, description_kk, description_ru, topic, difficulty, content, sort_order, created_at, mentor_track, required_level) VALUES ('00000000-0000-4000-8000-000000001018', 'Қазақ тіліне тән дыбыстар', 'Специфические звуки казахского', 'Ә, ғ, қ, ң, ө, ұ, ү, һ, і — 9 тән дыбысты меңгеру.', 'Ә, ғ, қ, ң, ө, ұ, ү, һ, і — девять специфических звуков.', 'phonetics', 'A1', '{"rule_ids": ["rule_18"]}', 18, '2026-04-21 21:35:28.434024+00', 'baitursynuly', 'A1') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, title_kk, title_ru, description_kk, description_ru, topic, difficulty, content, sort_order, created_at, mentor_track, required_level) VALUES ('00000000-0000-4000-8000-000000001020', 'Есімше формалары', 'Причастные формы', 'Осы, өткен, келер шақ есімшелері: оқитын (дағдылы), оқыған (өткен), оқыр (келер).', 'Причастия: оқитын (привычное / настояще-будущее), оқыған (прошедшее), оқыр (будущее).', 'grammar', 'B2', '{"rule_ids": ["rule_20"]}', 20, '2026-04-21 21:35:28.434024+00', 'baitursynuly', 'B2') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, title_kk, title_ru, description_kk, description_ru, topic, difficulty, content, sort_order, created_at, mentor_track, required_level) VALUES ('00000000-0000-4000-8000-000000001001', 'Амандасу және танысу', 'Приветствие и знакомство', 'Қазақша сәлемдесу, өзіңізді таныстыру, қарапайым сұрақ қою.', 'Казахские приветствия, как представиться, простые вопросы.', 'conversation', 'A1', '{"rule_ids": ["rule_01"]}', 1, '2026-04-21 21:35:28.434024+00', 'abai', 'A1') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, title_kk, title_ru, description_kk, description_ru, topic, difficulty, content, sort_order, created_at, mentor_track, required_level) VALUES ('00000000-0000-4000-8000-000000001019', 'Бас әріп ережелері', 'Правила заглавной буквы', 'Сөйлем басы, жалқы есімдер, географиялық атаулар, мекемелер мен ұйымдардың аттары.', 'Начало предложения, имена собственные, географические названия, наименования учреждений.', 'orthography', 'A2', '{"rule_ids": ["rule_19"]}', 19, '2026-04-21 21:35:28.434024+00', 'baitursynuly', 'A2') ON CONFLICT (id) DO NOTHING;
INSERT INTO lessons (id, title_kk, title_ru, description_kk, description_ru, topic, difficulty, content, sort_order, created_at, mentor_track, required_level) VALUES ('00000000-0000-4000-8000-000000001021', 'Қазақ мақал-мәтелдері', 'Казахские пословицы и поговорки', 'Халық даналығы, жиі кездесетін мақал-мәтелдер және олардың мағынасы.', 'Народная мудрость: частые пословицы и их значение.', 'culture', 'B1', '{"rule_ids": ["rule_21"]}', 21, '2026-04-21 21:35:28.434024+00', 'abai', 'B1') ON CONFLICT (id) DO NOTHING;
INSERT INTO test_questions (id, test_type, topic, difficulty, question_kk, question_ru, options, correct_answer, explanation_kk, explanation_ru) VALUES ('0206dd9f-9192-41c0-9fb7-489a4fb209eb', 'level', 'grammar', 'A1', 'Дұрыс жауапты таңдаңыз: Мен мектепке ___.', 'Выберите правильный ответ: Я в школу ___.', '["барамын", "барасың", "барады", "барамыз"]', 'барамын', '"Мен" жіктеу есімдігімен етістіктің 1-жақ жекеше түрі қолданылады: барамын.', 'С личным местоимением "Мен" используется форма 1-го лица единственного числа: барамын.') ON CONFLICT (id) DO NOTHING;
INSERT INTO test_questions (id, test_type, topic, difficulty, question_kk, question_ru, options, correct_answer, explanation_kk, explanation_ru) VALUES ('b3e640c6-cdaa-4dcf-8dc5-a0c9f4208f4a', 'level', 'vocabulary', 'A1', '"Мұғалім" сөзінің мағынасы:', 'Значение слова "Мұғалім":', '["Учитель", "Ученик", "Директор", "Врач"]', 'Учитель', 'Мұғалім — оқытушы, мектепте сабақ беретін адам.', 'Мұғалім — учитель, человек, который ведёт уроки в школе.') ON CONFLICT (id) DO NOTHING;
INSERT INTO test_questions (id, test_type, topic, difficulty, question_kk, question_ru, options, correct_answer, explanation_kk, explanation_ru) VALUES ('0eb16eea-747d-4688-bc8d-dce775c44151', 'level', 'grammar', 'A1', '"Ол кітап оқы___" — болымсыз етістіктің дұрыс формасын таңдаңыз.', '"Ол кітап оқы___" — выберите правильную отрицательную форму.', '["-майды", "-мады", "-мақ", "-мас"]', '-майды', 'Осы шақтағы болымсыздық: -майды/-мейді.', 'Отрицание в настоящем времени: -майды/-мейді.') ON CONFLICT (id) DO NOTHING;
