INSERT INTO test_questions (id, test_type, topic, difficulty, question_kk, question_ru, options, correct_answer, explanation_kk, explanation_ru) VALUES ('1854e81c-6c7c-4590-afcb-7bfd8b69bf25', 'level', 'grammar', 'A2', 'Ілік септігінің жалғауын дұрыс қойыңыз: бала___', 'Поставьте окончание родительного падежа: бала___', '["-ның", "-нің", "-дың", "-тың"]', '-ның', 'Дауысты дыбысқа аяқталған жуан буынды сөздерге -ның жалғанады.', 'К словам с твёрдым слогом, оканчивающимся на гласный, прибавляется -ның.') ON CONFLICT (id) DO NOTHING;
