INSERT INTO test_questions (id, test_type, topic, difficulty, question_kk, question_ru, options, correct_answer, explanation_kk, explanation_ru) VALUES ('0e13606e-21cc-403f-ad96-ef626688d1c3', 'level', 'grammar', 'B1', 'Қай сөйлемде көмектес септік қолданылған?', 'В каком предложении использован творительный падеж?', '["Мен досыммен бардым", "Мен мектепке бардым", "Мен кітап оқыдым", "Мен үйде отырмын"]', 'Мен досыммен бардым', 'Көмектес септік -мен/-бен/-пен жалғауларымен жасалады. "Досыммен" — көмектес септік.', 'Творительный падеж образуется окончаниями -мен/-бен/-пен. "Досыммен" — творительный падеж.') ON CONFLICT (id) DO NOTHING;
INSERT INTO test_questions (id, test_type, topic, difficulty, question_kk, question_ru, options, correct_answer, explanation_kk, explanation_ru) VALUES ('f513b5b9-cfae-4282-818d-ed9f81225f50', 'level', 'vocabulary', 'B1', '"Қастерлеу" сөзінің мағынасы:', 'Значение слова "Қастерлеу":', '["Ценить, беречь", "Ненавидеть", "Забывать", "Терять"]', 'Ценить, беречь', '"Қастерлеу" — қадірлеу, бағалау, сақтау.', '"Қастерлеу" — ценить, беречь, дорожить.') ON CONFLICT (id) DO NOTHING;
INSERT INTO test_questions (id, test_type, topic, difficulty, question_kk, question_ru, options, correct_answer, explanation_kk, explanation_ru) VALUES ('3e2cc79f-23e1-458e-9ce3-6212a24a08e5', 'level', 'grammar', 'B1', 'Септеулік шылауды табыңыз:', 'Найдите послелог:', '["туралы", "және", "бірақ", "себебі"]', 'туралы', '"Туралы" — септеулік шылау, "жайлы" мағынасын береді.', '"Туралы" — послелог, означает "о, про".') ON CONFLICT (id) DO NOTHING;
