INSERT INTO test_questions (id, test_type, topic, difficulty, question_kk, question_ru, options, correct_answer, explanation_kk, explanation_ru) VALUES ('d4e2a470-3c97-4992-9da7-31b0ba1c469b', 'level', 'grammar', 'A2', 'Өткен шақтың дұрыс формасы: Біз кеше кино___', 'Правильная форма прошедшего времени: Мы вчера кино___', '["көрдік", "көреміз", "көрген", "көрсек"]', 'көрдік', '"Біз" — 1-жақ көпше, жедел өткен шақ: көрдік.', '"Біз" — 1-е лицо множественного числа, недавнопрошедшее (жедел өткен шақ): көрдік.') ON CONFLICT (id) DO NOTHING;
INSERT INTO test_questions (id, test_type, topic, difficulty, question_kk, question_ru, options, correct_answer, explanation_kk, explanation_ru) VALUES ('e96aa208-eb86-4a51-af0f-d178ae17c334', 'level', 'grammar', 'B2', 'Күрделі сөйлемнің қай түрі: "Күн жауса, біз үйде отырамыз"?', 'Какой тип сложного предложения: "Күн жауса, біз үйде отырамыз"?', '["Шартты бағыныңқылы", "Мезгілді бағыныңқылы", "Себепті бағыныңқылы", "Салалас"]', 'Шартты бағыныңқылы', '"-са" жалғауы шарт білдіреді. Бұл — шартты бағыныңқылы сабақтас құрмалас сөйлем.', 'Суффикс "-са" выражает условие. Это — условное придаточное сложноподчинённое предложение.') ON CONFLICT (id) DO NOTHING;
