INSERT INTO test_questions (id, test_type, topic, difficulty, question_kk, question_ru, options, correct_answer, explanation_kk, explanation_ru) VALUES ('f146d067-5e17-40aa-824a-6d1c4af60065', 'kaztest', 'reading', 'B1', 'Мәтінді оқып, сұраққа жауап беріңіз: "Қазақстан — Орталық Азиядағы ең үлкен мемлекет. Астанасы — Астана қаласы." Қазақстанның астанасы қай қала?', 'Прочитайте текст и ответьте: "Қазақстан — крупнейшее государство в Центральной Азии. Столица — город Астана." Какой город является столицей Казахстана?', '["Астана", "Алматы", "Шымкент", "Қарағанды"]', 'Астана', 'Мәтінде "Астанасы — Астана қаласы" деп жазылған.', 'В тексте указано: "Столица — город Астана".') ON CONFLICT (id) DO NOTHING;
