INSERT INTO test_questions (id, test_type, topic, difficulty, question_kk, question_ru, options, correct_answer, explanation_kk, explanation_ru) VALUES ('886f2c88-f90b-4a66-b2f4-5e4795887687', 'level', 'grammar', 'C1', 'Төмендегі сөйлемдегі стилистикалық қатені табыңыз: "Мен бүгін базарға барып, нан мен сүт сатып алдым."', 'Найдите стилистическую ошибку: "Мен бүгін базарға барып, нан мен сүт сатып алдым."', '["Қатесі жоқ", "\"базарға\" орнына \"дүкенге\"", "\"сатып алдым\" орнына \"алдым\"", "\"барып\" орнына \"барды\""]', 'Қатесі жоқ', 'Сөйлемде стилистикалық қате жоқ.', 'В предложении нет стилистической ошибки.') ON CONFLICT (id) DO NOTHING;
