INSERT INTO test_questions (id, test_type, topic, difficulty, question_kk, question_ru, options, correct_answer, explanation_kk, explanation_ru) VALUES ('119ae37a-87ce-45df-b952-08f558a74e09', 'level', 'grammar', 'C1', 'Кіріккен сөзді табыңыз:', 'Найдите слитное слово:', '["бүгін", "үлкен бала", "қызыл алма", "жақсы адам"]', 'бүгін', '"Бүгін" — "бұл" + "күн" сөздерінен кіріккен. Қалғандары — сөз тіркестері.', '"Бүгін" — слитное слово от "бұл" + "күн". Остальные — словосочетания.') ON CONFLICT (id) DO NOTHING;
