INSERT INTO test_questions (id, test_type, topic, difficulty, question_kk, question_ru, options, correct_answer, explanation_kk, explanation_ru) VALUES ('047ea2d8-3ad5-4a38-86eb-3196c5552ddb', 'kaztest', 'listening', 'B1', '"Ертең жаңбыр жауады" — бұл сөйлем не туралы?', '"Ертең жаңбыр жауады" — о чём это предложение?', '["Ауа райы", "Тамақ", "Көлік", "Жұмыс"]', 'Ауа райы', 'Жаңбыр — ауа райы туралы сөз.', 'Дождь — погодное явление.') ON CONFLICT (id) DO NOTHING;
