INSERT INTO test_questions (id, test_type, topic, difficulty, question_kk, question_ru, options, correct_answer, explanation_kk, explanation_ru) VALUES ('33f41353-aefb-4ea5-9c55-3474ff19625c', 'level', 'grammar', 'C2', '«Жел тұрмаса, шөптің басы қимылдамайды» — мұнда қандай стильдік тәсіл?', '«Жел тұрмаса, шөптің басы қимылдамайды» — какой стилистический приём?', '["Мақал (нет дыма без огня)", "Метафора", "Эпитет", "Гипербола"]', 'Мақал (нет дыма без огня)', 'Бұл қазақ мақалы, «нет дыма без огня» мағынасында.', 'Это казахская пословица — эквивалент «нет дыма без огня».') ON CONFLICT (id) DO NOTHING;
