INSERT INTO test_questions (id, test_type, topic, difficulty, question_kk, question_ru, options, correct_answer, explanation_kk, explanation_ru) VALUES ('5812cd7c-cc82-46a0-941f-500e77d87af3', 'level', 'grammar', 'C2', '«Ат үсті қарау» тіркесінің мағынасы:', 'Значение выражения «ат үсті қарау»:', '["Рассматривать поверхностно", "Смотреть внимательно", "Осматривать лошадь", "Готовиться"]', 'Рассматривать поверхностно', '«Ат үсті» — үстірт, жеңіл-желпі деген мағынада.', '«Ат үсті» — поверхностно, мимоходом.') ON CONFLICT (id) DO NOTHING;
INSERT INTO test_questions (id, test_type, topic, difficulty, question_kk, question_ru, options, correct_answer, explanation_kk, explanation_ru) VALUES ('900f5452-bf80-4e7d-adc9-965177989682', 'level', 'vocabulary', 'C2', '«Жүрегіне қанжар сұққандай» дегеніміз:', 'Значение «жүрегіне қанжар сұққандай»:', '["Глубоко ранить (эмоционально)", "Обрадовать", "Успокоить", "Помочь"]', 'Глубоко ранить (эмоционально)', 'Жан дүниесін қатты жаралау мағынасындағы көркем теңеу.', 'Художественное сравнение, означающее сильную душевную рану.') ON CONFLICT (id) DO NOTHING;
INSERT INTO test_questions (id, test_type, topic, difficulty, question_kk, question_ru, options, correct_answer, explanation_kk, explanation_ru) VALUES ('d2d29337-c3f6-4931-95f0-e6883f03c125', 'level', 'grammar', 'C2', 'Қай нұсқада көркем әдебиет стилінің белгісі бар?', 'В каком варианте — признак художественного стиля?', '["Ай нұрын шашқан түн", "Жиналыс сағат 9-да басталады", "Қаулы бекітілді", "Хабарламаны қабылдаңыз"]', 'Ай нұрын шашқан түн', 'Көркемдегіш тәсіл (метафора) — көркем әдебиет стиліне тән.', 'Метафора — признак художественного стиля.') ON CONFLICT (id) DO NOTHING;
INSERT INTO test_questions (id, test_type, topic, difficulty, question_kk, question_ru, options, correct_answer, explanation_kk, explanation_ru) VALUES ('df830570-eea0-4fcc-9bf6-1ed72e6e2bd0', 'level', 'grammar', 'A1', 'Көптік жалғауды дұрыс қойыңыз: кітап___', 'Поставьте правильное окончание множественного числа: кітап___', '["-тар", "-лар", "-дар", "-тер"]', '-тар', '"Кітап" сөзі араб тілінен енген кірме сөз; тонкая огласовкасына (і — жіңішке дауысты) қарамастан, әдеби нормада -тар жалғауымен жазылады. Бұл — лексикалық ерекшелік.', 'Слово "кітап" — арабизм-исключение. Несмотря на тонкую гласную "і", в литературной норме закреплено окончание -тар (а не -тер по правилу сингармонизма).');
INSERT INTO test_questions (id, test_type, topic, difficulty, question_kk, question_ru, options, correct_answer, explanation_kk, explanation_ru) VALUES ('7a6a60e8-a666-422b-b3c9-7cf921fa5cc7', 'level', 'grammar', 'A2', 'Тәуелдік жалғауды дұрыс қойыңыз: Менің кітаб___', 'Поставьте притяжательное окончание: Менің кітаб___', '["-ім", "-ің", "-і", "-іміз"]', '-ім', '"Кітап" — жіңішке негіз ("і"), сондықтан тәуелдік 1-жақ жекеше -ім. Дауыссыздан басталатын негіз дауыстыдан басталатын қосымша алдында "п→б" алмасуынан кейін: кітабім.', '"Кітап" — мягкая основа (узкая гласная "і"), поэтому 1 л. ед.ч. — -ім. Перед гласным аффиксом "п" переходит в "б": кітабім.') ON CONFLICT (id) DO NOTHING;
INSERT INTO test_questions (id, test_type, topic, difficulty, question_kk, question_ru, options, correct_answer, explanation_kk, explanation_ru) VALUES ('e5babf07-bbc6-4ac7-8acd-453dca08ac14', 'level', 'grammar', 'B2', 'Есімшенің дұрыс формасы: Кеше ___ адам бүгін келді.', 'Правильная форма причастия: Человек, который вчера ___, сегодня пришёл.', '["кеткен", "кететін", "кетер", "кетіп"]', 'кеткен', 'Өткен шақ есімше -ған/-ген/-қан/-кен жұрнағымен жасалады.', 'Причастие прошедшего времени образуется суффиксом -ған/-ген/-қан/-кен.') ON CONFLICT (id) DO NOTHING;
INSERT INTO test_questions (id, test_type, topic, difficulty, question_kk, question_ru, options, correct_answer, explanation_kk, explanation_ru) VALUES ('58a73ffd-6807-4e89-9577-ab75163c8e57', 'level', 'vocabulary', 'B2', '"Кеңістік" сөзінің синонимі:', 'Синоним слова "Кеңістік":', '["Аумақ, кеңдік", "Тарылық", "Тереңдік", "Биіктік"]', 'Аумақ, кеңдік', '"Кеңістік" — кең аумақ, ашық алаң, көлем; синонимдері: аумақ, кеңдік, алаң.', '"Кеңістік" — пространство, простор, объём; синонимы: аумақ (территория), кеңдік (ширина/простор).');
INSERT INTO test_questions (id, test_type, topic, difficulty, question_kk, question_ru, options, correct_answer, explanation_kk, explanation_ru) VALUES ('dd2d1b3e-2406-4992-a483-a09f7926bfa4', 'kaztest', 'listening', 'B2', 'Дұрыс нұсқаны таңдаңыз: Біз ___ мектепте оқыдық.', 'Выберите правильный вариант: Мы ___ учились в школе.', '["бір", "бірге", "бірлік", "бірден"]', 'бірге', '"Бірге" — вместе, көмектес мәнді үстеу.', '"Бірге" — вместе, наречие совместности.') ON CONFLICT (id) DO NOTHING;
INSERT INTO test_questions (id, test_type, topic, difficulty, question_kk, question_ru, options, correct_answer, explanation_kk, explanation_ru) VALUES ('9eac5f7f-911a-45ea-a069-c7869803dd30', 'kaztest', 'listening', 'A1', 'Тыңдаңыз: "Сағат неше?" Сұрақтың мағынасы не?', 'Послушайте: "Сағат неше?" Что означает вопрос?', '["Который час?", "Как дела?", "Сколько лет?", "Где ты?"]', 'Который час?', '"Сағат қанша?" — уақытты сұрау.', '"Сағат қанша?" — вопрос о времени.') ON CONFLICT (id) DO NOTHING;
INSERT INTO test_questions (id, test_type, topic, difficulty, question_kk, question_ru, options, correct_answer, explanation_kk, explanation_ru) VALUES ('dd66609e-613c-4528-8324-76767a3b48f2', 'kaztest', 'reading', 'B1', '"Қазақ халқының Наурыз мейрамы — көктемнің келуін білдіреді". Наурыз қашан тойланады?', '"Наурыз — символ прихода весны". Когда отмечается Наурыз?', '["Көктемде", "Жазда", "Күзде", "Қыста"]', 'Көктемде', 'Көктем — весна, Наурыз 22 наурызда (март).', 'Весной, 22 марта.') ON CONFLICT (id) DO NOTHING;
